func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := goquery.NewDocumentFromReader(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	title := strings.TrimSpace(doc.Find("title").First().Text())

	description, _ := doc.Find(`meta[name="description"]`).First().Attr("content")
	description = strings.TrimSpace(description)

	if description == "" {
		description, _ = doc.Find(`meta[property="og:description"]`).First().Attr("content")
		description = strings.TrimSpace(description)
	}
	if title == "" {
		t, _ := doc.Find(`meta[property="og:title"]`).First().Attr("content")
		title = strings.TrimSpace(t)
	}

	return title, description
}

func isBlockedHost(host string) bool {
	h := strings.ToLower(strings.TrimSpace(host))
	if h == "" {
		return true
	}
	if h == "localhost" || h == "localhost." {
		return true
	}
	if strings.HasSuffix(h, ".local") || strings.HasSuffix(h, ".localhost") {
		return true
	}
	return false
}

func resolveAndValidateHost(host string) (net.IP, error) {
	// Block direct IP literals that are private/loopback/etc.
	if ip := net.ParseIP(host); ip != nil {
		if isPrivateIP(ip) {
			return nil, errors.New("private ip")
		}
		return ip, nil
	}

	ips, err := net.LookupIP(host)
	if err != nil || len(ips) == 0 {
		return nil, errors.New("dns lookup failed")
	}

	// Prefer IPv4 public; otherwise allow public IPv6 if present.
	var firstPublic net.IP
	for _, ip := range ips {
		if !isPrivateIP(ip) {
			firstPublic = ip
			break
		}
	}
	if firstPublic == nil {
		return nil, errors.New("no public ip")
	}
	return firstPublic, nil
}

func isPrivateIP(ip net.IP) bool {
	if ip == nil {
		return true
	}

	// IPv4 checks
	if ip4 := ip.To4(); ip4 != nil {
		switch {
		case ip4[0] == 10:
			return true
		case ip4[0] == 127:
			return true
		case ip4[0] == 169 && ip4[1] == 254:
			return true
		case ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31:
			return true
		case ip4[0] == 192 && ip4[1] == 168:
			return true
		case ip4[0] == 0:
			return true
		default:
			return false
		}
	}

	// IPv6: block loopback, link-local, unique local, multicast, unspecified
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsMulticast() || ip.IsUnspecified() {
		return true
	}
	// Unique local fc00::/7
	if len(ip) == net.IPv6len && (ip[0]&0xfe) == 0xfc {
		return true
	}

	return false
}

func errorsIsContext(err error) bool {
	return errors.Is(err, context.Canceled) || errors.Is(err, context.DeadlineExceeded) ||
		strings.Contains(err.Error(), context.Canceled.Error()) ||
		strings.Contains(err.Error(), context.DeadlineExceeded.Error())
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	_ = e.Start(":8080")
}

