func validateNoPrivateOrLocalhost(u *url.URL) error {
	host := u.Hostname()
	if host == "" {
		return errors.New("URL must include a hostname")
	}

	// Fast-path for obvious localhost names.
	lh := strings.ToLower(host)
	if lh == "localhost" || strings.HasSuffix(lh, ".localhost") {
		return errors.New("localhost is not allowed")
	}

	// If host is an IP literal, validate directly.
	if ip := net.ParseIP(host); ip != nil {
		if isDisallowedIP(ip) {
			return errors.New("private or local network addresses are not allowed")
		}
		return nil
	}

	// Otherwise, resolve and validate all A/AAAA records.
	ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
	defer cancel()

	ips, err := net.DefaultResolver.LookupIPAddr(ctx, host)
	if err != nil {
		return errors.New("failed to resolve hostname")
	}
	for _, ip := range ips {
		if isDisallowedIP(ip.IP) {
			return errors.New("private or local network addresses are not allowed")
		}
	}
	return nil
}

func isDisallowedIP(ip net.IP) bool {
	if ip == nil {
		return true
	}
	// Normalize to 16-byte form for checks.
	ip = ip.To16()
	if ip == nil {
		return true
	}

	// Unspecified, loopback, multicast.
	if ip.IsUnspecified() || ip.IsLoopback() || ip.IsMulticast() {
		return true
	}

	// Link-local.
	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Private ranges (IPv4) + CGNAT.
	if v4 := ip.To4(); v4 != nil {
		if v4[0] == 10 {
			return true
		}
		if v4[0] == 172 && v4[1]&0xF0 == 16 {
			return true
		}
		if v4[0] == 192 && v4[1] == 168 {
			return true
		}
		// 127.0.0.0/8
		if v4[0] == 127 {
			return true
		}
		// 169.254.0.0/16
		if v4[0] == 169 && v4[1] == 254 {
			return true
		}
		// 100.64.0.0/10 (CGNAT)
		if v4[0] == 100 && (v4[1]&0xC0) == 64 {
			return true
		}
		// 0.0.0.0/8
		if v4[0] == 0 {
			return true
		}
		// 224.0.0.0/4 multicast already covered, but keep conservative
		if v4[0] >= 224 {
			return true
		}
		return false
	}

	// IPv6 unique local fc00::/7
	if ip[0]&0xFE == 0xFC {
		return true
	}
	// IPv6 loopback ::1 handled by IsLoopback; also block ::/128 handled by IsUnspecified.
	// IPv6 link-local fe80::/10 handled by IsLinkLocalUnicast.
	return false
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := html.Parse(bytes.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var title, desc string
	var walk func(*html.Node)
	walk = func(n *html.Node) {
		if n == nil || (title != "" && desc != "") {
			return
		}

		if n.Type == html.ElementNode {
			switch strings.ToLower(n.Data) {
			case "title":
				if title == "" && n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				var name, property, content string
				for _, a := range n.Attr {
					switch strings.ToLower(a.Key) {
					case "name":
						name = strings.ToLower(strings.TrimSpace(a.Val))
					case "property":
						property = strings.ToLower(strings.TrimSpace(a.Val))
					case "content":
						content = strings.TrimSpace(a.Val)
					}
				}
				if desc == "" && content != "" && (name == "description" || property == "og:description") {
					desc = content
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			walk(c)
			if title != "" && desc != "" {
				return
			}
		}
	}
	walk(doc)

	return title, desc
}

