	"github.com/labstack/echo/v4"
)

// Request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}
	req.URL = strings.TrimSpace(req.URL)
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Missing url"})
	}

	parsedURL, err := url.ParseRequestURI(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}
	if parsedURL.Host == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL host"})
	}

	// Basic SSRF mitigation: block localhost / private / link-local / multicast / etc.
	if err := rejectPrivateHost(parsedURL.Hostname()); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": err.Error()})
	}

	httpClient := &http.Client{
		Timeout: 8 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			if len(via) >= 5 {
				return fmt.Errorf("too many redirects")
			}
			// Re-check redirects for private hosts
			if err := rejectPrivateHost(req.URL.Hostname()); err != nil {
				return err
			}
			return nil
		},
	}

	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")
	httpReq.Header.Set("Accept", "text/html,application/xhtml+xml")

	resp, err := httpClient.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("Upstream returned HTTP %d", resp.StatusCode)})
	}

	// Limit read to avoid huge responses
	const maxBytes = 2 << 20 // 2MB
	body, err := io.ReadAll(io.LimitReader(resp.Body, maxBytes))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := goquery.NewDocumentFromReader(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	title := strings.TrimSpace(doc.Find("title").First().Text())

	// Prefer standard meta description; fall back to og:description
	description, _ := doc.Find(`meta[name="description"]`).First().Attr("content")
	description = strings.TrimSpace(description)
	if description == "" {
		description, _ = doc.Find(`meta[property="og:description"]`).First().Attr("content")
		description = strings.TrimSpace(description)
	}

	return title, description
}

func rejectPrivateHost(host string) error {
	// If it's an IP literal, validate directly.
	if ip := net.ParseIP(host); ip != nil {
		if isPrivateOrLocalIP(ip) {
			return fmt.Errorf("URL host is not allowed")
		}
		return nil
	}

	// Resolve DNS with a short timeout and validate all A/AAAA results.
	ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
	defer cancel()

	ips, err := net.DefaultResolver.LookupIP(ctx, "ip", host)
	if err != nil {
		return fmt.Errorf("Failed to resolve host")
	}
	for _, ip := range ips {
		if isPrivateOrLocalIP(ip) {
			return fmt.Errorf("URL host is not allowed")
		}
	}
	return nil
}

func isPrivateOrLocalIP(ip net.IP) bool {
	if ip == nil {
		return true
	}
	// Normalize to 16-byte form where possible.
	ip = ip.To16()
	if ip == nil {
		return true
	}

	// Unspecified / loopback
	if ip.IsUnspecified() || ip.IsLoopback() {
		return true
	}

	// Link-local, multicast
	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsMulticast() {
		return true
	}

	// IPv4-mapped?
	if v4 := ip.To4(); v4 != nil {
		// Private ranges: 10/8, 172.16/12, 192.168/16
		if v4[0] == 10 {
			return true
		}
		if v4[0] == 172 && v4[1]&0xF0 == 16 {
			return true
		}
		if v4[0] == 192 && v4[1] == 168 {
			return true
		}
		// 127/8 loopback already covered by IsLoopback, but keep explicit
		if v4[0] == 127 {
			return true
		}
		// 169.254/16 link-local
		if v4[0] == 169 && v4[1] == 254 {
			return true
		}
		// 0.0.0.0/8
		if v4[0] == 0 {
			return true
		}
		// 100.64.0.0/10 (CGNAT)
		if v4[0] == 100 && (v4[1]&0xC0) == 64 {
			return true
		}
		return false
	}

	// IPv6 unique local fc00::/7
	if ip[0]&0xFE == 0xFC {
		return true
	}
	// IPv6 link-local fe80::/10
	if ip[0] == 0xFE && (ip[1]&0xC0) == 0x80 {
		return true
	}
	// IPv6 loopback ::1 handled by IsLoopback
	return false
}

