				return errors.New("too many redirects")
			}
			if err := validateNoPrivateOrLocalhost(req.URL); err != nil {
				return errors.New("redirect to disallowed host")
			}
			return nil
		},
	}
}

func safeDialContext(d *net.Dialer) func(ctx context.Context, network, address string) (net.Conn, error) {
	return func(ctx context.Context, network, address string) (net.Conn, error) {
		host, port, err := net.SplitHostPort(address)
		if err != nil {
			// address might be missing port; fall back to raw address
			host = address
			port = ""
		}

		ips, err := net.DefaultResolver.LookupIPAddr(ctx, host)
		if err != nil {
			return nil, err
		}
		for _, ip := range ips {
			if isDisallowedIP(ip.IP) {
				return nil, errors.New("dial to disallowed IP")
			}
		}

		if port == "" {
			return d.DialContext(ctx, network, host)
		}
		return d.DialContext(ctx, network, net.JoinHostPort(host, port))
	}
}

func validateNoPrivateOrLocalhost(u *url.URL) error {
	host := u.Hostname()
	if host == "" {
		return errors.New("missing host")
	}

	// Block obvious localhost names early
	h := strings.ToLower(host)
	if h == "localhost" || strings.HasSuffix(h, ".localhost") {
		return errors.New("localhost blocked")
	}

	// If host is an IP literal, validate directly.
	if ip := net.ParseIP(host); ip != nil {
		if isDisallowedIP(ip) {
			return errors.New("disallowed ip")
		}
		return nil
	}

	// For domain names, resolve and validate all IPs.
	ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
	defer cancel()

	ips, err := net.DefaultResolver.LookupIPAddr(ctx, host)
	if err != nil {
		return err
	}
	for _, ip := range ips {
		if isDisallowedIP(ip.IP) {
			return errors.New("disallowed resolved ip")
		}
	}
	return nil
}

func isDisallowedIP(ip net.IP) bool {
	if ip == nil {
		return true
	}

	// Normalize IPv4-mapped IPv6 to IPv4 when applicable.
	if v4 := ip.To4(); v4 != nil {
		ip = v4
	} else if len(ip) == net.IPv6len {
		ip = ip.To16()
	}

	// Unspecified, loopback, multicast, link-local
	if ip.IsUnspecified() || ip.IsLoopback() || ip.IsMulticast() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// IPv4 private ranges + CGNAT + broadcast-ish
	if v4 := ip.To4(); v4 != nil {
		// 10.0.0.0/8
		if v4[0] == 10 {
			return true
		}
		// 172.16.0.0/12
		if v4[0] == 172 && v4[1]&0xF0 == 16 {
			return true
		}
		// 192.168.0.0/16
		if v4[0] == 192 && v4[1] == 168 {
			return true
		}
		// 127.0.0.0/8 loopback (already covered by IsLoopback, but keep explicit)
		if v4[0] == 127 {
			return true
		}
		// 169.254.0.0/16 link-local (already covered)
		if v4[0] == 169 && v4[1] == 254 {
			return true
		}
		// 100.64.0.0/10 (CGNAT)
		if v4[0] == 100 && (v4[1]&0xC0) == 64 {
			return true
		}
		// 0.0.0.0/8
		if v4[0] == 0 {
			return true
		}
		return false
	}

	// IPv6 unique-local fc00::/7, link-local fe80::/10
	if ip16 := ip.To16(); ip16 != nil && len(ip16) == net.IPv6len {
		// fc00::/7
		if ip16[0]&0xFE == 0xFC {
			return true
		}
		// fe80::/10
		if ip16[0] == 0xFE && (ip16[1]&0xC0) == 0x80 {
			return true
		}
	}

	return false
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := goquery.NewDocumentFromReader(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	title := strings.TrimSpace(doc.Find("title").First().Text())
	if title != "" {
		title = normalizeSpace(title)
	}

	// Prefer meta[name=description], then og:description
	desc := ""
	if s, ok := doc.Find(`meta[name="description"]`).First().Attr("content"); ok {
		desc = strings.TrimSpace(s)
	}
	if desc == "" {
		if s, ok := doc.Find(`meta[property="og:description"]`).First().Attr("content"); ok {
			desc = strings.TrimSpace(s)
		}
	}
	desc = normalizeSpace(desc)

	// Keep responses reasonable
	if len(title) > 300 {
		title = title[:300]
	}
	if len(desc) > 1000 {
		desc = desc[:1000]
	}

	return title, desc
}

func normalizeSpace(s string) string {
	return strings.Join(strings.Fields(s), " ")
}

