func extractTitleAndDescription(r io.Reader) (title string, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var walk func(n *html.Node)
	walk = func(n *html.Node) {
		if n == nil {
			return
		}

		if n.Type == html.ElementNode {
			switch strings.ToLower(n.Data) {
			case "title":
				if title == "" {
					title = strings.TrimSpace(textContent(n))
				}
			case "meta":
				var name, property, content string
				for _, a := range n.Attr {
					switch strings.ToLower(a.Key) {
					case "name":
						name = strings.ToLower(strings.TrimSpace(a.Val))
					case "property":
						property = strings.ToLower(strings.TrimSpace(a.Val))
					case "content":
						content = strings.TrimSpace(a.Val)
					}
				}
				if description == "" {
					if name == "description" && content != "" {
						description = content
					} else if property == "og:description" && content != "" {
						description = content
					}
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			// Early exit if both found
			if title != "" && description != "" {
				return
			}
			walk(c)
		}
	}
	walk(doc)

	return title, description, nil
}

func textContent(n *html.Node) string {
	var b strings.Builder
	var f func(*html.Node)
	f = func(x *html.Node) {
		if x == nil {
			return
		}
		if x.Type == html.TextNode {
			b.WriteString(x.Data)
		}
		for c := x.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(n)
	return b.String()
}

func main() {
	e := echo.New()

	e.POST("/preview", FetchURLPreview)

	// Simple health endpoint
	e.GET("/", func(c echo.Context) error {
		return c.String(http.StatusOK, "ok")
	})

	if err := e.Start(":8080"); err != nil && !errors.Is(err, http.ErrServerClosed) {
		e.Logger.Fatal(err)
	}
}

