			continue
		}
		if !isBlockedIP(ip) {
			return ip, nil
		}
	}
	return nil, errors.New("blocked")
}

type pinnedKey struct{}

type pinnedInfo struct {
	ip   string
	port string
}

func withPinned(ctx context.Context, ip, port string) context.Context {
	return context.WithValue(ctx, pinnedKey{}, &pinnedInfo{ip: ip, port: port})
}

func pinnedFromContext(ctx context.Context) *pinnedInfo {
	if ctx == nil {
		return nil
	}
	if v, ok := ctx.Value(pinnedKey{}).(*pinnedInfo); ok {
		return v
	}
	return nil
}

func isBlockedIP(ip net.IP) bool {
	if ip == nil {
		return true
	}
	ip = ip.To16()
	if ip == nil {
		return true
	}

	if ip.IsUnspecified() || ip.IsLoopback() {
		return true
	}
	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}
	if ip.IsMulticast() {
		return true
	}

	if v4 := ip.To4(); v4 != nil {
		if v4[0] == 10 {
			return true
		}
		if v4[0] == 172 && v4[1]&0xF0 == 16 {
			return true
		}
		if v4[0] == 192 && v4[1] == 168 {
			return true
		}
		if v4[0] == 127 {
			return true
		}
		if v4[0] == 169 && v4[1] == 254 {
			return true
		}
		if v4[0] == 0 {
			return true
		}
		if v4[0] == 100 && (v4[1]&0xC0) == 64 {
			return true
		}
		if v4[0] == 192 && v4[1] == 0 && v4[2] == 0 {
			return true
		}
		if (v4[0] == 192 && v4[1] == 0 && v4[2] == 2) ||
			(v4[0] == 198 && v4[1] == 51 && v4[2] == 100) ||
			(v4[0] == 203 && v4[1] == 0 && v4[2] == 113) {
			return true
		}
		return false
	}

	if ip[0]&0xFE == 0xFC {
		return true
	}
	if ip[0] == 0xFE && (ip[1]&0xC0) == 0x80 {
		return true
	}
	if ip[0] == 0x20 && ip[1] == 0x01 && ip[2] == 0x0d && ip[3] == 0xb8 {
		return true
	}

	return false
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := goquery.NewDocumentFromReader(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	title := strings.TrimSpace(doc.Find("title").First().Text())

	description := ""
	if v, ok := doc.Find(`meta[name="description"]`).Attr("content"); ok {
		description = strings.TrimSpace(v)
	}
	if description == "" {
		if v, ok := doc.Find(`meta[property="og:description"]`).Attr("content"); ok {
			description = strings.TrimSpace(v)
		}
	}
	if description == "" {
		if v, ok := doc.Find(`meta[name="twitter:description"]`).Attr("content"); ok {
			description = strings.TrimSpace(v)
		}
	}

	return title, description
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

