	if description == "" {
		description, _ = doc.Find(`meta[property="og:description"]`).First().Attr("content")
		description = strings.TrimSpace(description)
	}
	if description == "" {
		description, _ = doc.Find(`meta[name="twitter:description"]`).First().Attr("content")
		description = strings.TrimSpace(description)
	}

	return title, description
}

func isPrivateOrLocalHost(host string) bool {
	h := strings.ToLower(strings.TrimSpace(host))
	if h == "" {
		return true
	}
	if h == "localhost" || h == "localhost." {
		return true
	}
	if strings.HasSuffix(h, ".localhost") || strings.HasSuffix(h, ".localhost.") {
		return true
	}

	ip := net.ParseIP(h)
	if ip == nil {
		// Not an IP literal; allow (DNS could still resolve privately, but this is a basic guard).
		return false
	}

	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// IPv4 private ranges + CGNAT.
	if ip4 := ip.To4(); ip4 != nil {
		switch {
		case ip4[0] == 10:
			return true
		case ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31:
			return true
		case ip4[0] == 192 && ip4[1] == 168:
			return true
		case ip4[0] == 127:
			return true
		case ip4[0] == 169 && ip4[1] == 254:
			return true
		case ip4[0] == 100 && ip4[1] >= 64 && ip4[1] <= 127:
			return true
		}
		return false
	}

	// IPv6 private/local ranges.
	if ip.IsPrivate() {
		return true
	}
	// Unique local addresses fc00::/7
	if len(ip) == net.IPv6len && (ip[0]&0xfe) == 0xfc {
		return true
	}
	return false
}

