		if v4[0] == 127 {
			return true
		}
		// 169.254.0.0/16 link-local already covered, but keep explicit.
		if v4[0] == 169 && v4[1] == 254 {
			return true
		}
		// CGNAT 100.64.0.0/10
		if v4[0] == 100 && (v4[1]&0xC0) == 64 {
			return true
		}
		// 0.0.0.0/8
		if v4[0] == 0 {
			return true
		}
		// 224.0.0.0/4 multicast already covered, but keep explicit.
		if v4[0] >= 224 {
			return true
		}
		return false
	}

	// IPv6 unique local (fc00::/7)
	if ip[0]&0xFE == 0xFC {
		return true
	}
	// IPv6 link-local (fe80::/10)
	if ip[0] == 0xFE && (ip[1]&0xC0) == 0x80 {
		return true
	}
