		if ip[0] == 127 {
			return true
		}
		// 169.254.0.0/16 link-local already covered
		if ip[0] == 169 && ip[1] == 254 {
			return true
		}
		// 0.0.0.0/8
		if ip[0] == 0 {
			return true
		}
		// 100.64.0.0/10 (CGNAT)
		if ip[0] == 100 && (ip[1]&0xC0) == 64 {
			return true
		}
		return false
	}

	// IPv6 private/ULA (fc00::/7) and other special ranges
	if len(ip) == net.IPv6len {
		// Unique local addresses fc00::/7
		if ip[0]&0xFE == 0xFC {
			return true
		}
		// Loopback ::1 handled by IsLoopback
		// Link-local fe80::/10 handled by IsLinkLocalUnicast
		// Documentation 2001:db8::/32 (not routable)
		if ip[0] == 0x20 && ip[1] == 0x01 && ip[2] == 0x0d && ip[3] == 0xb8 {
			return true
		}
	}

	return false
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := goquery.NewDocumentFromReader(bytes.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	// Title
	title := strings.TrimSpace(doc.Find("title").First().Text())

	// Prefer standard meta description; fallback to og:description/twitter:description
	getMeta := func(selector string) string {
		v, _ := doc.Find(selector).First().Attr("content")
		return strings.TrimSpace(v)
	}

	description := getMeta(`meta[name="description"]`)
	if description == "" {
		description = getMeta(`meta[property="og:description"]`)
	}
	if description == "" {
		description = getMeta(`meta[name="twitter:description"]`)
	}

	if len(title) > maxTitleLen {
		title = title[:maxTitleLen]
	}
	if len(description) > maxDescriptionLen {
		description = description[:maxDescriptionLen]
	}
	return title, description
}

