	}

	parsed, err := url.Parse(req.URL)
	if err != nil || parsed.Scheme == "" || parsed.Host == "" {
		return ctx.JSON(http.StatusBadRequest, errorResponse{Error: "invalid url"})
	}
	if parsed.Scheme != "http" && parsed.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, errorResponse{Error: "only http/https URLs are supported"})
	}

	client := &http.Client{
