	}
	// Fallback to Open Graph.
	if v := strings.TrimSpace(doc.Find(`meta[property="og:description"]`).First().AttrOr("content", "")); v != "" {
		return v
	}
	// Fallback to Twitter.
	if v := strings.TrimSpace(doc.Find(`meta[name="twitter:description"]`).First().AttrOr("content", "")); v != "" {
		return v
	}
	return ""
}

