	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("Upstream HTTP %d", resp.StatusCode)})
	}

	ct := resp.Header.Get("Content-Type")
	if ct != "" && !strings.Contains(strings.ToLower(ct), "text/html") && !strings.Contains(strings.ToLower(ct), "application/xhtml+xml") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL did not return HTML content"})
	}

	// Limit read to avoid memory exhaustion
	const maxBodyBytes = 1 << 20 // 1 MiB
	body, err := io.ReadAll(io.LimitReader(resp.Body, maxBodyBytes))
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := goquery.NewDocumentFromReader(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	title := strings.TrimSpace(doc.Find("title").First().Text())

	// Prefer standard meta description; fall back to og:description
	desc := ""
	if s, ok := doc.Find(`meta[name="description"]`).First().Attr("content"); ok {
		desc = strings.TrimSpace(s)
	}
	if desc == "" {
		if s, ok := doc.Find(`meta[property="og:description"]`).First().Attr("content"); ok {
			desc = strings.TrimSpace(s)
		}
	}

	// Keep responses reasonably sized
	title = truncateRunes(title, 200)
	desc = truncateRunes(desc, 500)

	return title, desc
}

func truncateRunes(s string, max int) string {
	if max <= 0 || s == "" {
		return ""
	}
	r := []rune(s)
	if len(r) <= max {
		return s
	}
	return string(r[:max])
}

// --- SSRF mitigations ---

func isDisallowedHost(host string) bool {
	h := strings.ToLower(strings.TrimSpace(host))
	// Basic hostname blocks (still also validated via IP resolution)
	switch h {
	case "localhost", "localhost.localdomain":
		return true
	}
	// Block obvious local TLD
	if strings.HasSuffix(h, ".local") {
		return true
	}
	return false
}

func validateNoPrivateIP(host string) error {
	// If host is an IP literal, check directly
	if ip := net.ParseIP(host); ip != nil {
		if isPrivateOrDisallowedIP(ip) {
			return errors.New("disallowed ip")
		}
		return nil
	}

	// Resolve DNS and check all results
	ips, err := net.DefaultResolver.LookupIP(context.Background(), "ip", host)
	if err != nil {
		return err
	}
	for _, ip := range ips {
		if isPrivateOrDisallowedIP(ip) {
			return errors.New("disallowed ip")
		}
	}
	return nil
}

func isPrivateOrDisallowedIP(ip net.IP) bool {
	if ip == nil {
		return true
	}
	// Normalize
	if v4 := ip.To4(); v4 != nil {
		ip = v4
	}

	// Unspecified / loopback / multicast / link-local
	if ip.IsUnspecified() || ip.IsLoopback() || ip.IsMulticast() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Private ranges
	if isInCIDR(ip, "10.0.0.0/8") ||
		isInCIDR(ip, "172.16.0.0/12") ||
		isInCIDR(ip, "192.168.0.0/16") ||
		isInCIDR(ip, "127.0.0.0/8") ||
		isInCIDR(ip, "169.254.0.0/16") ||
		// CGNAT
		isInCIDR(ip, "100.64.0.0/10") {
		return true
	}

	// IPv6 private / special
	if ip.To4() == nil {
		if isInCIDR(ip, "::1/128") || // loopback
			isInCIDR(ip, "fc00::/7") || // ULA
			isInCIDR(ip, "fe80::/10") || // link-local
			isInCIDR(ip, "::/128") { // unspecified
			return true
		}
	}

	return false
}

func isInCIDR(ip net.IP, cidr string) bool {
	_, n, err := net.ParseCIDR(cidr)
	if err != nil {
		return false
	}
	return n.Contains(ip)
}

func newSafeHTTPClient() *http.Client {
	dialer := &net.Dialer{
		Timeout:   3 * time.Second,
		KeepAlive: 30 * time.Second,
	}

	transport := &http.Transport{
		Proxy: http.ProxyFromEnvironment,
		DialContext: func(ctx context.Context, network, addr string) (net.Conn, error) {
			host, port, err := net.SplitHostPort(addr)
			if err != nil {
				return nil, err
			}

			// Block direct IP connections to private/disallowed ranges
			if ip := net.ParseIP(host); ip != nil {
				if isPrivateOrDisallowedIP(ip) {
					return nil, errors.New("blocked address")
				}
			} else {
				// Resolve and block if any result is private/disallowed
				ips, err := net.DefaultResolver.LookupIP(ctx, "ip", host)
				if err != nil {
					return nil, err
				}
				for _, ip := range ips {
					if isPrivateOrDisallowedIP(ip) {
						return nil, errors.New("blocked address")
					}
				}
			}

			return dialer.DialContext(ctx, network, net.JoinHostPort(host, port))
		},
		TLSHandshakeTimeout:   5 * time.Second,
		ResponseHeaderTimeout: 5 * time.Second,
		ExpectContinueTimeout: 1 * time.Second,
		IdleConnTimeout:       30 * time.Second,
		MaxIdleConns:          20,
		MaxConnsPerHost:       5,
	}

	return &http.Client{
		Transport: transport,
		Timeout:   10 * time.Second,
		// Prevent open redirect SSRF chains
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			if len(via) >= 3 {
				return errors.New("too many redirects")
			}
			u := req.URL
			if u == nil {
				return errors.New("invalid redirect")
			}
			if u.Scheme != "http" && u.Scheme != "https" {
				return errors.New("redirect scheme not allowed")
			}
			if isDisallowedHost(u.Hostname()) {
				return errors.New("redirect host not allowed")
			}
			if err := validateNoPrivateIP(u.Hostname()); err != nil {
				return errors.New("redirect resolves to disallowed ip")
			}
			return nil
		},
	}
}

