	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("Upstream HTTP %d", resp.StatusCode)})
	}

	// Limit read to avoid huge responses
	const maxBytes = 2 << 20 // 2MB
	body, err := io.ReadAll(io.LimitReader(resp.Body, maxBytes))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := goquery.NewDocumentFromReader(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	title := strings.TrimSpace(doc.Find("title").First().Text())

	// Prefer standard meta description
	description, _ := doc.Find(`meta[name="description"]`).First().Attr("content")
	description = strings.TrimSpace(description)

	// Fallbacks commonly used by sites
	if description == "" {
		description, _ = doc.Find(`meta[property="og:description"]`).First().Attr("content")
		description = strings.TrimSpace(description)
	}
	if description == "" {
		description, _ = doc.Find(`meta[name="twitter:description"]`).First().Attr("content")
		description = strings.TrimSpace(description)
	}

	return title, description
}

