	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/PuerkitoBio/goquery"
	"github.com/labstack/echo/v4"
)

type PreviewRequest struct {
	URL string `json:"url"`
}

type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

const (
	maxHTMLBytes      = 1 << 20 // 1 MiB
	requestTimeout    = 5 * time.Second
	maxRedirects      = 5
	userAgent         = "Mozilla/5.0 (compatible; URLPreviewBot/1.0)"
	allowedHTTPStatus = 200
)

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}
	req.URL = strings.TrimSpace(req.URL)
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url is required"})
	}

	parsedURL, err := url.Parse(req.URL)
	if err != nil || parsedURL == nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}
	if parsedURL.Host == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL host is required"})
	}
	// Disallow credentials in URL to avoid leaking secrets / SSRF tricks.
	if parsedURL.User != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Userinfo in URL is not allowed"})
	}

	// SSRF protection: block private/loopback/link-local/etc. and localhost.
	if err := validateNoPrivateIP(parsedURL); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is not allowed"})
	}

	client := newSafeHTTPClient()

	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL"})
	}
	httpReq.Header.Set("User-Agent", userAgent)
	httpReq.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != allowedHTTPStatus {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Upstream returned non-200 status"})
	}

	ct := resp.Header.Get("Content-Type")
	if ct != "" && !looksLikeHTMLContentType(ct) {
		return ctx.JSON(http.StatusUnsupportedMediaType, map[string]string{"error": "URL did not return HTML"})
	}

	limited := io.LimitReader(resp.Body, maxHTMLBytes+1)
	body, err := io.ReadAll(limited)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to read response body"})
	}
	if int64(len(body)) > maxHTMLBytes {
		return ctx.JSON(http.StatusRequestEntityTooLarge, map[string]string{"error": "Response too large"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
